import"./hoisted.Bs9XmLrN.js";document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".product-card-with-spec .product-card-trigger").forEach(e=>{e.addEventListener("click",()=>{const d=e.getAttribute("data-spec-target");if(!d)return;const r=document.getElementById(d);if(!r)return;if(!r.hasAttribute("hidden")){r.setAttribute("hidden",""),e.setAttribute("aria-expanded","false");const t=e.querySelector(".spec-toggle-label");t&&(t.textContent="View specs ↓")}else{document.querySelectorAll(".product-card-with-spec .spec-panel").forEach(i=>{i.setAttribute("hidden","");const c=document.querySelector(`[data-spec-target="${i.id}"]`);if(c){c.setAttribute("aria-expanded","false");const s=c.querySelector(".spec-toggle-label");s&&(s.textContent="View specs ↓")}}),r.removeAttribute("hidden"),e.setAttribute("aria-expanded","true");const t=e.querySelector(".spec-toggle-label");t&&(t.textContent="Hide specs ↑")}})})});
